      const fx = px - x0, fy = py - y0;
      const i00 = gi(x0,   y0  ), i10 = gi(x0+1, y0  );
      const i01 = gi(x0,   y0+1), i11 = gi(x0+1, y0+1);
      const w00 = (1-fx)*(1-fy), w10 = fx*(1-fy);
